// c_n := Fourier coefficient of q^n in j(tau), for n = -1, 0, 1, 2, ...
// OEIS A000521
const C = {
 "-1": 1n,
  "0": 744n,
  "1": 196884n,
  "2": 21493760n,
  "3": 864299970n,
  "4": 20245856256n,
  "5": 333202640600n,
  "6": 4252023300096n,
  "7": 44656994071935n,
  "8": 401490886656000n,
  "9": 3176440229784420n,
 "10": 22567393309593600n,
};
const slider = $('#w-j-N'), lbl = $('#w-j-Nv'), out = $('#w-j-out');
function render(){
  const N = +slider.value;
  lbl.textContent = 'N=' + N;
  let s = 'n      c_n  (Fourier coefficient of q^n in j)\n';
  s += '---    ----------------------------------------\n';
  for(let n=-1;n<=N;n++){
    s += (n===-1 ? '-1' : ' '+String(n)).padStart(3,' ');
    s += '    ' + C[String(n)].toString() + '\n';
  }
  out.textContent = s.trimEnd();
}
slider.addEventListener('input', render);
render();

