// Thompson series head coefficients (tr g|V_n for n=-1..4).
// Classical data: T_{1A} = j - 744; T_{2A}, T_{2B}, T_{3A}, T_{5A} are the Hauptmoduls
// for Gamma_0(2)+ , Gamma_0(2), Gamma_0(3)+, Gamma_0(5)+ respectively.
const T = {
  "1A": {
    label: "T_{1A}(τ) = J(τ) = j(τ) − 744",
    coefs: ["1","0","196884","21493760","864299970","20245856256"],
    group: "SL_2(ℤ)     (genus 0; normalizer of itself)",
  },
  "2A": {
    label: "T_{2A}(τ)   (Hauptmodul for Γ₀(2)+)",
    coefs: ["1","0","4372","96256","1240002","10698752"],
    group: "Γ₀(2)+      (genus 0)",
  },
  "2B": {
    label: "T_{2B}(τ)   (Hauptmodul for Γ₀(2))",
    coefs: ["1","0","276","−2048","11202","−49152"],
    group: "Γ₀(2)        (genus 0)",
  },
  "3A": {
    label: "T_{3A}(τ)   (Hauptmodul for Γ₀(3)+)",
    coefs: ["1","0","783","8672","65367","371520"],
    group: "Γ₀(3)+      (genus 0)",
  },
  "5A": {
    label: "T_{5A}(τ)   (Hauptmodul for Γ₀(5)+)",
    coefs: ["1","0","134","760","3345","12256"],
    group: "Γ₀(5)+      (genus 0)",
  },
};
const sel = $('#w-t-g'), out = $('#w-t-out');
function render(){
  const t = T[sel.value];
  let s = '';
  s += t.label + '\n';
  s += 'modular group:   ' + t.group + '\n\n';
  s += 'n      tr(g | V^♮_n)\n';
  s += '---    -----------------\n';
  const ns = [-1,0,1,2,3,4];
  ns.forEach((n,i)=>{
    s += (n===-1 ? '-1' : ' '+String(n)).padStart(3,' ');
    s += '    ' + t.coefs[i] + '\n';
  });
  s += '\n';
  s += 'n = -1 coefficient is always 1: the vacuum V^♮_{-1} is the trivial rep,\n';
  s += 'and every group element acts as the identity on it.\n';
